import { configureStore } from "@reduxjs/toolkit";
import cartReducer from "./cartSlice";

// Check if this is a fresh session (app is not opened again)
const isFreshSession = localStorage.getItem("isFreshSession") === "true";
let cartItems = [];

if (isFreshSession) {
  // Clear the cart items from localStorage for a fresh session
  localStorage.removeItem("cartItems");
} else {
  // Retrieve the cart items from localStorage if it's not a fresh session
  const cartItemsFromLocalStorage = localStorage.getItem("cartItems");
  cartItems = cartItemsFromLocalStorage ? JSON.parse(cartItemsFromLocalStorage) : [];
}

const initialState = {
  cart: {
    items: cartItems,
  },
};

const store = configureStore({
  reducer: {
    cart: cartReducer,
  },
  preloadedState: initialState,
});

export default store;

// Infer the `RootState` and `AppDispatch` types from the store itself
export type RootState = ReturnType<typeof store.getState>;
export type AppDispatch = typeof store.dispatch;






